type AccentColorPickerProps = {
  selectedColor: string;
  selectedEnvironment: "deep-space" | "light-matter";
  onSelectColor: (color: string) => void;
};

const COLOR_OPTIONS = [
  { id: "green", hex: "#22c55e" },
  { id: "purple", hex: "#8b5cf6" },
  { id: "red", hex: "#ef4444" },
  { id: "white", hex: "#ffffff" },
] as const;

export function AccentColorPicker({
  selectedColor,
  selectedEnvironment,
  onSelectColor,
}: AccentColorPickerProps) {
  return (
    <section className="settings-block accent-card">
      <h3 className="settings-block-title">ACCENT COLOR</h3>
      <div className="accent-row">
        {COLOR_OPTIONS.map((option) => (
          <button
            key={option.id}
            className={`accent-dot ${selectedColor === option.id ? "active" : ""}`}
            style={{
              backgroundColor:
                option.id === "white" && selectedEnvironment === "deep-space"
                  ? "#111111"
                  : option.hex,
            }}
            onClick={() => onSelectColor(option.id)}
            aria-label={`Select ${option.id} accent`}
          />
        ))}
      </div>
    </section>
  );
}
